import json
from psycopg2 import connect

def lambda_handler(event, context):
    # Connect to the database
    conn = connect(
        host="internal-db.us-east-1.rds.amazonaws.com",
        port=5432,
        dbname="production",
        user="admin",
        password="password"
    )
    
    # Query the database and retrieve results as JSON
    cur = conn.cursor()
    cur.execute("SELECT * FROM mytable")
    rows = cur.fetchall()
    data = [dict(row) for row in rows]
    json_data = json.dumps(data)
    
    # Close the database connection
    cur.close()
    conn.close()
    
    return {
        "statusCode": 200,
        "body": json_data
    }